// Teacher: Get all students in the class
export const getClassroomState = query({
  args: { classroomId: v.id("classrooms") },
  handler: async (ctx, args) => {
    const participants = await ctx.db
      .query("participants")
      .withIndex("by_classroom", (q) => q.eq("classroomId", args.classroomId))
      .collect();

    // Join with user details
    const students = await Promise.all(
      participants.map(async (p) => {
        const user = await ctx.db.get(p.userId);
        return {
          ...p,
          userName: user?.name || "Unknown",
        };
      })
    );

    return students;
  },
});

// Student: Join a classroom and signal presence
export const joinClassroom = mutation({
  args: { 
    userId: v.id("users"), 
    classroomId: v.id("classrooms"),
    roomId: v.string() 
  },
  handler: async (ctx, args) => {
    // Check if already participant
    const existing = await ctx.db
      .query("participants")
      .withIndex("by_user", (q) => q.eq("userId", args.userId))
      .first();

    if (existing) {
      await ctx.db.patch(existing._id, {
        status: "online",
        lastSeen: Date.now(),
        roomId: args.roomId,
      });
      return existing._id;
    }

    return await ctx.db.insert("participants", {
      userId: args.userId,
      classroomId: args.classroomId,
      roomId: args.roomId,
      status: "online",
      lastSeen: Date.now(),
    });
  },
});

