import Editor from "@monaco-editor/react";
import { RoomProvider, useStorage, useMutation as useLiveblocksMutation, useOthers } from '../../liveblocks.config';
import { useMutation } from "convex/react";
import { api } from "../../convex/_generated/api";
import { ClientSideSuspense } from "@liveblocks/react";
import { Loader2, Hand, Users as UsersIcon, Check } from 'lucide-react';

// The Inner Editor Component
const EditorInstance = ({ roomId, studentId }: { roomId: string, studentId: string }) => {
  const code = useStorage((root) => root.code);
  const others = useOthers();

  // Liveblocks: Sync Code
  const updateCode = useLiveblocksMutation(({ storage }, newCode) => {
    storage.set("code", newCode);
  }, []);

  // Convex: Hand Raising
  const raiseHand = useMutation(api.classroom.raiseHand);
  const [isHandRaised, setIsHandRaised] = useState(false);

  const toggleHand = () => {
    const newState = !isHandRaised;
    setIsHandRaised(newState);
    raiseHand({ roomId, raised: newState });
  };

  const teacherPresent = others.some(user => user.info?.role === 'teacher');

  return (
    <div className="h-full flex flex-col bg-white">
      {/* Toolbar */}
      <div className="flex items-center justify-between px-4 py-2 border-b border-gray-100 bg-white">
        <div className="flex items-center gap-2">
          <span className="text-sm font-bold text-black">Main.py</span>
          {teacherPresent && (
             <span className="flex items-center gap-1 text-xs bg-black text-white px-2 py-0.5 rounded-full">
               <UsersIcon size={10} /> Mentor Online
             </span>
          )}
        </div>
        <button 
          onClick={toggleHand}
          className={`flex items-center gap-2 px-3 py-1.5 rounded-lg text-sm font-medium transition-all ${
            isHandRaised 
              ? 'bg-yellow-100 text-yellow-800 border border-yellow-200' 
              : 'bg-white text-gray-600 border border-gray-200 hover:bg-gray-50'
          }`}
        >
          <Hand size={14} className={isHandRaised ? 'fill-yellow-800' : ''} />
          <span>{isHandRaised ? 'Hand Raised' : 'Ask for Help'}</span>
        </button>
      </div>

      {/* Monaco Editor */}
      <div className="flex-grow relative">
        <Editor
          height="100%"
          defaultLanguage="python"
          value={code}
          onChange={(value) => updateCode(value || "")}
          theme="light"
          options={{
            minimap: { enabled: false },
            fontSize: 14,
            fontFamily: 'Inter, monospace',
            lineNumbers: 'on',
            scrollBeyondLastLine: false,
            automaticLayout: true,
            padding: { top: 16 }
          }}
        />
      </div>
    </div>
  );
};

