import { mutation, query } from "./_generated/server";
import { v } from "convex/values";

// Helper type for implicit any in demo
type Context = any;

// Query: Teacher Dashboard uses this to get the live list of students
// Now fetches from 'workspaces' and joins with 'users'
export const getClassroomState = query({
  handler: async (ctx: Context) => {
    const workspaces = await ctx.db.query("workspaces").collect();

    // Manual join to get user names
    const enriched = await Promise.all(workspaces.map(async (ws: any) => {
        const user = await ctx.db.get(ws.userId);
        return {
            _id: ws._id,
            name: user?.name || "Unknown Student",
            role: user?.role || "student",
            roomId: user?.tokenIdentifier || "unknown", // Using tokenIdentifier as session/room ID for compatibility
            status: ws.status,
            isHandRaised: ws.handRaised,
            lastSeen: ws.lastActiveAt,
            lastErrorMessage: ws.lastErrorMessage
        };
    }));
    return enriched;
  },
});

// Mutation: Join the classroom
// Creates User and Workspace entries instead of just 'participants'
export const joinClassroom = mutation({
  args: { 
    name: v.string(),
    roomId: v.string(), // e.g. "room-user-123", we use this as tokenIdentifier
    role: v.string()    // relaxed type to accept string from frontend
  },
  handler: async (ctx: Context, args: any) => {
    // 1. Find or Create User
    let user = await ctx.db.query("users")
        .withIndex("by_token", (q: any) => q.eq("tokenIdentifier", args.roomId))
        .first();

    if (!user) {
        const userId = await ctx.db.insert("users", {
            tokenIdentifier: args.roomId,
            name: args.name,
            email: "demo@oneported.com",
            role: args.role === "teacher" ? "teacher" : "student",
            hasCompletedOnboarding: false
        });
        user = await ctx.db.get(userId);
    } else {
        // Update name if changed
        if (user.name !== args.name) {
             await ctx.db.patch(user._id, { name: args.name });
        }
    }

    // 2. Find or Create Workspace
    let workspace = await ctx.db.query("workspaces")
        .withIndex("by_user", (q: any) => q.eq("userId", user._id))
        .first();

    if (workspace) {
        await ctx.db.patch(workspace._id, { lastActiveAt: Date.now() });
    } else {
        await ctx.db.insert("workspaces", {
            userId: user._id,
            status: "idle",
            handRaised: false,
            lastSavedCode: "",
            installedModules: [],
            lastActiveAt: Date.now()
        });
    }
  },
});

// Mutation: Student raises (or lowers) hand
export const raiseHand = mutation({
  args: { 
    roomId: v.string(), 
    raised: v.boolean() 
  },
  handler: async (ctx: Context, args: any) => {
    const user = await ctx.db.query("users")
        .withIndex("by_token", (q: any) => q.eq("tokenIdentifier", args.roomId))
        .first();

    if (!user) return;

    const workspace = await ctx.db.query("workspaces")
        .withIndex("by_user", (q: any) => q.eq("userId", user._id))
        .first();

    if (workspace) {
        await ctx.db.patch(workspace._id, { handRaised: args.raised });
    }
  },
});

