  }, []);
  return loaded 
    ? React.createElement(React.Fragment, null, children) 
    : React.createElement(React.Fragment, null, fallback);
};

// --- Exports ---
export const RoomProvider = USE_MOCK ? MockRoomProvider : RealRoomProvider;
export const useOthers = USE_MOCK ? useMockOthers : useRealOthers;
export const useStorage = USE_MOCK ? useMockStorage : useRealStorage;
export const useMutation = USE_MOCK ? useMockMutation : useRealMutation;
export const useMyPresence = USE_MOCK ? useMockMyPresence : useRealMyPresence;
export const ClientSideSuspense = USE_MOCK ? MockClientSideSuspense : RealClientSideSuspense;

import React, { useState } from 'react';
import { Monitor, User, ArrowRight, BookOpen } from 'lucide-react';

interface LoginScreenProps {
  onJoin: (name: string, role: 'student' | 'teacher') => void;
}

const LoginScreen: React.FC<LoginScreenProps> = ({ onJoin }) => {
  const [selectedRole, setSelectedRole] = useState<'student' | 'teacher' | null>(null);
  const [name, setName] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (name && selectedRole) {
      onJoin(name, selectedRole);
    }
  };

  if (!selectedRole) {
    return (
      <div className="min-h-screen bg-white flex flex-col items-center justify-center p-4 animate-fade-in-up">
        <div className="text-center mb-12">
          <h1 className="text-4xl font-bold tracking-tight mb-4">Welcome to OnePorted</h1>
          <p className="text-gray-500">Select your role to access the workspace.</p>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-6 w-full max-w-2xl">
          {/* Student Card */}
          <button
            onClick={() => setSelectedRole('student')}
            className="group relative p-8 rounded-2xl border border-gray-200 hover:border-black transition-all text-left hover:shadow-xl"
          >
            <div className="w-12 h-12 bg-gray-50 rounded-full flex items-center justify-center mb-6 group-hover:bg-black group-hover:text-white transition-colors">
              <User size={24} />
            </div>
            <h3 className="text-2xl font-bold mb-2">Student</h3>
            <p className="text-gray-500 mb-8">Join a classroom, access resources, and work on projects.</p>
            <div className="flex items-center text-sm font-medium">
              Continue as Student <ArrowRight size={16} className="ml-2 group-hover:translate-x-1 transition-transform"/>
            </div>
          </button>

          {/* Teacher Card */}
          <button
            onClick={() => setSelectedRole('teacher')}
            className="group relative p-8 rounded-2xl border border-gray-200 hover:border-black transition-all text-left hover:shadow-xl"
          >
            <div className="w-12 h-12 bg-gray-50 rounded-full flex items-center justify-center mb-6 group-hover:bg-black group-hover:text-white transition-colors">
              <Monitor size={24} />
            </div>
            <h3 className="text-2xl font-bold mb-2">Teacher</h3>
            <p className="text-gray-500 mb-8">Monitor progress, manage assignments, and assist students.</p>
            <div className="flex items-center text-sm font-medium">
              Open Dashboard <ArrowRight size={16} className="ml-2 group-hover:translate-x-1 transition-transform"/>
            </div>
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-white flex flex-col items-center justify-center p-4 animate-fade-in-up">
      <div className="w-full max-w-md">
        <button 
          onClick={() => setSelectedRole(null)}
          className="text-sm text-gray-500 hover:text-black mb-8 flex items-center"
        >
          ← Back to role selection
        </button>

        <div className="text-center mb-8">
           <div className="w-16 h-16 bg-black text-white rounded-2xl mx-auto flex items-center justify-center mb-6 shadow-lg">
             {selectedRole === 'student' ? <User size={32} /> : <Monitor size={32} />}
           </div>
           <h2 className="text-3xl font-bold mb-2">
             Join as {selectedRole === 'student' ? 'Student' : 'Teacher'}
           </h2>
           <p className="text-gray-500">Enter your credentials to continue.</p>
        </div>

        <form onSubmit={handleSubmit} className="space-y-4">
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Full Name</label>
            <input
              type="text"
              value={name}
              onChange={(e) => setName(e.target.value)}
              placeholder={selectedRole === 'student' ? "e.g. John Doe" : "e.g. Prof. Smith"}
              className="w-full px-4 py-3 border border-gray-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-black/5 focus:border-black transition-all"
              required
            />
          </div>

          <button
            type="submit"
            className="w-full py-4 bg-black text-white rounded-lg font-bold text-lg hover:bg-gray-800 transition-all shadow-lg hover:shadow-xl hover:-translate-y-0.5"
          >
            {selectedRole === 'student' ? 'Enter Classroom' : 'Launch Dashboard'}
          </button>
        </form>
      </div>
    </div>
  );
};

export default LoginScreen;

import React, { useState, useEffect } from 'react';
import { ConvexProvider, ConvexReactClient, useMutation } from "convex/react";
import { api } from "./convex/_generated/api";
import Header from './components/Layout/Header';
import Hero from './components/LandingPage/Hero';
import StatsGrid from './components/LandingPage/StatsGrid';
import CommunityHub from './components/LandingPage/CommunityHub';
import Footer from './components/Layout/Footer';
import UtilitiesPage from './components/Utilities/UtilitiesPage';
import PythonEditor from './components/Editor/PythonEditor';
import TeacherDashboard from './components/Classroom/TeacherDashboard';
import CollaborativeEditor from './components/Classroom/CollaborativeEditor';
import LoginScreen from './components/Auth/LoginScreen';
import { ArrowLeft } from 'lucide-react';

// ----------------------------------------------------------------------
// CONFIGURATION
// ----------------------------------------------------------------------
// To test on multiple devices:
// 1. Run `npx convex dev` locally
// 2. Replace this URL with your REAL Convex URL
const CONVEX_URL = "https://humorous-wombat-123.convex.cloud";

const convex = new ConvexReactClient(CONVEX_URL);

// Wrapper to handle Mutation calls inside the provider
const AppContent: React.FC = () => {
  const [currentView, setCurrentView] = useState('home');
  const [selectedRoomId, setSelectedRoomId] = useState<string | null>(null);

  // Auth State
  const [user, setUser] = useState<{name: string, role: string, id: string} | null>(null);

  // Mutations
  const joinClassroom = useMutation(api.classroom.joinClassroom);

  // Initialize Session ID (Device ID)
  useEffect(() => {
    let deviceId = localStorage.getItem('oneported_device_id');
    if (!deviceId) {
      deviceId = `user-${Math.random().toString(36).substr(2, 9)}`;
      localStorage.setItem('oneported_device_id', deviceId);
    }
  }, []);

  const handleLogin = async (name: string, role: 'student' | 'teacher') => {
    const deviceId = localStorage.getItem('oneported_device_id') || `user-${Date.now()}`;

    // Register User in Backend
    // In a real app, this happens via OAuth/Clerk
    await joinClassroom({
      name: name,
      roomId: deviceId, // We use Device ID as the Room/User ID for this demo
      role: role
    });

    setUser({ name, role, id: deviceId });
    setCurrentView(role === 'teacher' ? 'classroom' : 'home');
  };

  const handleJoinRoom = (roomId: string) => {
    setSelectedRoomId(roomId);
    setCurrentView('active-session');
  };

  // If not logged in, show Login Screen
  if (!user) {
    return <LoginScreen onJoin={handleLogin} />;
  }

  return (
    <div className="min-h-screen flex flex-col bg-white">
      {/* Navigation Header */}
      <Header onNavigate={setCurrentView} currentView={currentView} />

      {/* Main Content Area */}
      <main className="flex-grow">
        {currentView === 'home' && (
          <>
            <Hero />
            <section className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-12">
              <StatsGrid />
            </section>
            <section className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-16">
              <CommunityHub />
            </section>
          </>
        )}

        {currentView === 'utilities' && (
          <UtilitiesPage onNavigate={setCurrentView} />
        )}

        {currentView === 'python-editor' && (
          <PythonEditor />
        )}

        {/* Classroom Views */}
        {currentView === 'classroom' && (
          user.role === 'teacher' ? (
            <TeacherDashboard onJoinRoom={handleJoinRoom} />
          ) : (
             // Student View: Their Collaborative Workspace
             <div className="h-[calc(100vh-80px)]">
               <CollaborativeEditor 
                 studentId={user.id} 
                 userName={user.name} 
               />
             </div>
          )
        )}

        {/* Active Session View (When Teacher joins a student room) */}
        {currentView === 'active-session' && selectedRoomId && (
            <div className="flex flex-col h-[calc(100vh-80px)]">
                <div className="bg-gray-100 border-b border-gray-200 px-4 py-2 flex items-center gap-2">
                    <button onClick={() => setCurrentView('classroom')} className="flex items-center gap-1 text-sm text-gray-600 hover:text-black">
                        <ArrowLeft size={16} /> Back to Dashboard
                    </button>
                    <div className="h-4 w-px bg-gray-300 mx-2"></div>
                    <span className="text-sm font-medium">Viewing Student Session</span>
                </div>
                <div className="flex-grow">
                  <CollaborativeEditor 
                      studentId={selectedRoomId}
                      userName="Student" 
                  />
                </div>
            </div>
        )}
      </main>

      {currentView === 'home' && <Footer />}
    </div>
  );
};

export default function App() {
  return (
    <ConvexProvider client={convex}>
      <AppContent />
    </ConvexProvider>
  );
}
